import React, { useState, ChangeEvent, FormEvent } from "react";
import ExportInventoryButton from "./ExportInventoryButton";
import InventoryStatus from "./InventoryStatus";
import ProductDetailsView from "./ProductDetailsView";
import "./InventoryPage.css";

interface InventoryItem {
    id: number;
    name: string;
    category: string;
    stock: number;
    price: number;
    threshold: number;
    description?: string;
}

const sampleInventory: InventoryItem[] = [
    { id: 1, name: "Laptop", category: "Hardware", stock: 3, price: 1200, threshold: 5, description: "High-performance laptop" },
    { id: 2, name: "Headphones", category: "Audio", stock: 15, price: 200, threshold: 5, description: "Noise-canceling headphones" },
    { id: 3, name: "Mouse", category: "Accessories", stock: 1, price: 50, threshold: 5, description: "Wireless mouse" },
];

export default function InventoryPage() {
    const [inventory, setInventory] = useState<InventoryItem[]>(sampleInventory);
    const [selectedProduct, setSelectedProduct] = useState<InventoryItem | null>(null);
    const [newProduct, setNewProduct] = useState<Omit<InventoryItem, "id" | "threshold">>({
        name: "",
        category: "",
        stock: 0,
        price: 0,
        description: "",
    });

    const handleInputChange = (
        e: ChangeEvent<HTMLInputElement>
    ) => {
        const { name, value } = e.target;
        setNewProduct((prev) => ({
            ...prev,
            [name]: name === "stock" || name === "price"
                ? Number(value)
                : value,
        }));
    };

    const handleCreateProduct = (e: FormEvent) => {
        e.preventDefault();
        const id = inventory.length > 0 ? Math.max(...inventory.map((i) => i.id)) + 1 : 1;
        const product: InventoryItem = {
            id,
            name: newProduct.name,
            category: newProduct.category,
            stock: newProduct.stock,
            price: newProduct.price,
            threshold: newProduct.stock,
            description: newProduct.description || "",
        };
        setInventory((prev) => [...prev, product]);
        setNewProduct({ name: "", category: "", stock: 0, price: 0, description: "" });
    };

    const handleSelectProduct = (productId: number) => {
        const prod = inventory.find((item) => item.id === productId) || null;
        setSelectedProduct(prod);
    };

    const handleCloseDetails = () => {
        setSelectedProduct(null);
    };

    return (
        <div className="inventory-page-container">
            <h2>Inventory Management</h2>

            {/* Yeni Ürün Oluşturma Formu */}
            <form className="create-product-form" onSubmit={handleCreateProduct}>
                <input
                    name="name"
                    type="text"
                    placeholder="Ürün Adı"
                    value={newProduct.name}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="category"
                    type="text"
                    placeholder="Ürün Tipi"
                    value={newProduct.category}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="stock"
                    type="number"
                    placeholder="Adet / Miktar"
                    value={newProduct.stock}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="price"
                    type="number"
                    placeholder="Fiyat"
                    value={newProduct.price}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="description"
                    type="text"
                    placeholder="Açıklama (isteğe bağlı)"
                    value={newProduct.description}
                    onChange={handleInputChange}
                />
                <button type="submit" className="create-product-btn">
                    Oluştur
                </button>
            </form>

            {/* Stok Durumu ve Detay Görüntüleme */}
            <InventoryStatus items={inventory} onSelectItem={handleSelectProduct} />

            {/* Detay Görünümü */}
            {selectedProduct && (
                <ProductDetailsView
                    product={selectedProduct}
                    onClose={handleCloseDetails}
                />
            )}

            {/* CSV / PDF Aktarımı */}
            <ExportInventoryButton items={inventory} />
        </div>
    );
}
